ALTER TABLE public.companies ADD COLUMN IF NOT EXISTS workspace_type text; ALTER TABLE public.companies ADD COLUMN IF NOT EXISTS primary_module text; UPDATE public.companies SET workspace_type = CASE WHEN sector_type = 'clinic' THEN 'medical' WHEN sector_type = 'fnb' THEN 'food' ELSE workspace_type END, primary_module = CASE WHEN sector_type = 'clinic' THEN 'medical_clinics' WHEN sector_type = 'fnb' THEN 'food_restaurants' ELSE primary_module END WHERE workspace_type IS NULL OR primary_module IS NULL; ALTER TABLE public.companies DROP CONSTRAINT IF EXISTS companies_workspace_type_check; ALTER TABLE public.companies ADD CONSTRAINT companies_workspace_type_check CHECK (workspace_type IS NULL OR workspace_type IN ('medical','food')); ALTER TABLE public.companies DROP CONSTRAINT IF EXISTS companies_primary_module_check; ALTER TABLE public.companies ADD CONSTRAINT companies_primary_module_check CHECK (primary_module IS NULL OR primary_module IN ('medical_clinics','food_restaurants')); ALTER TABLE public.evaluation_templates ADD COLUMN IF NOT EXISTS workspace_type text; ALTER TABLE public.evaluation_templates DROP CONSTRAINT IF EXISTS evaluation_templates_workspace_type_check; ALTER TABLE public.evaluation_templates ADD CONSTRAINT evaluation_templates_workspace_type_check CHECK (workspace_type IS NULL OR workspace_type IN ('medical','food'));